    currentPrice: o?.currentPrice,
    volume24h: o?.volume24h,
    liquidity: o?.liquidity,
    whyThisOpportunity: o?.whyThisOpportunity
  }));

  return {
    summary: result?.summary,
    top5,
    fetchedAt: result?.fetchedAt,
    totalFound: opportunities.length
  };
}

