import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const discoveryBatch = await callMcpSkillsParallel({
    label: "sports-trending-discovery",
    calls: [
      {
        key: "trendingSports",
        toolId,
        toolName: "discover_trending_markets",
        args: { category: "sports", limit: 15 }
      }
    ]
  });

  const trendingResult =
    discoveryBatch.results.find((entry) => entry.key === "trendingSports" && entry.status === "fulfilled")?.value || null;

  const markets = Array.isArray(trendingResult?.trendingMarkets) ? trendingResult.trendingMarkets : [];

  const candidateSet = markets.map((m) => ({
    title: m?.title,
    slug: m?.slug,
    url: m?.url,
    currentPrice: m?.currentPrice,
    priceDirection: m?.priceDirection,
    whyTrending: m?.whyTrending,
    volumeVsAverage: m?.volumeVsAverage,
    trendScore: m?.trendScore,
    category: m?.category,
    signal: m?.signal
  }));

  const semanticTop = pickTopSemanticCandidates({
    target: "sports trending market with the strongest volumeVsAverage signal and clear trend narrative alignment",
    candidates: candidateSet,
    requiredTerms: ["sports"],
    avoidTerms: [],
    limit: 5
  });

  const parseVolumeVsAverage = (value) => {
    if (typeof value !== "string") return null;
    const s = value.trim().toLowerCase();
    const xMatch = s.match(/(\d+(?:\.\d+)?)\s*x/);
    if (xMatch) return parseFloat(xMatch[1]);
    const pctMatch = s.match(/([+-]?\d+(?:\.\d+)?)\s*%/);
    if (pctMatch) return Math.abs(parseFloat(pctMatch[1])) / 100;
    return null;
  };

  const detectAlignment = (priceDirection, whyTrending) => {
    const narrative = `${whyTrending || ""}`.toLowerCase();
    const direction = `${priceDirection || ""}`.toLowerCase();

    const upWords = ["up", "higher", "rising", "surging", "spiking", "jump", "gain", "bull", "bullish"];
    const downWords = ["down", "lower", "falling", "dropping", "sliding", "decline", "bear", "bearish"];

    const narrativeUp = upWords.some((w) => narrative.includes(w));
    const narrativeDown = downWords.some((w) => narrative.includes(w));
    const dirUp = direction.includes("up");
    const dirDown = direction.includes("down");

    const aligns =
      (dirUp && narrativeUp) ||
      (dirDown && narrativeDown) ||
      (!direction && (narrativeUp || narrativeDown));

    return {
      aligns,
      rationale: aligns
        ? "priceDirection aligns with the trend narrative in whyTrending"
        : "priceDirection does not clearly align with the trend narrative in whyTrending"
    };
  };

  const scored = markets
    .map((m, index) => {
      const signalValue = parseVolumeVsAverage(m?.volumeVsAverage);
      return {
        rank: index + 1,
        title: m?.title,
        slug: m?.slug,
        url: m?.url,
        currentPrice: m?.currentPrice,
        priceDirection: m?.priceDirection,
        whyTrending: m?.whyTrending,
        volumeVsAverage: m?.volumeVsAverage,
        trendScore: m?.trendScore,
        signalValue,
        alignment: detectAlignment(m?.priceDirection, m?.whyTrending)
      };
    })
